.darma-loader-darma-custom-527 {color: var(--loader-color, #0ea5e9);
   height: 30px;
   aspect-ratio: 2;
   background: radial-gradient(farthest-side,currentColor 15%,#0000 18%)0 0/50% 100%, radial-gradient(50% 100% at 50% 160%,currentColor 95%,#0000) 0 0 /50% 50%, radial-gradient(50% 100% at 50% -60%,currentColor 95%,#0000) 0 100%/50% 50%;
   background-repeat: repeat-x;
   -webkit-mask: radial-gradient(50% 100%,currentColor 95%,#0000) 0 100%/50% 0% repeat-x;
   animation: darma-loader-darma-custom-527-l3 1s infinite alternate ease-in;
}
@keyframes darma-loader-darma-custom-527-l3  {
  0%, 70% {-webkit-mask-size:50% 100%}
85% {-webkit-mask-size:50% 0}
100% {-webkit-mask-size:50% 100%}
}

